(function(w){"use strict";const ID="force-formula";function compute(x){const m=Number(x.mass),a=Number(x.acceleration);if(!Number.isFinite(m)||!Number.isFinite(a))return{error:"질량과 가속도를 입력해 주세요."};return{value:m*a};}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>질량 (kg)</label><input class="hm-calc-input" inputmode="decimal" data-key="mass" placeholder="" value=""></div><div class="hm-calc-field"><label>가속도 (m/s²)</label><input class="hm-calc-input" inputmode="decimal" data-key="acceleration" placeholder="" value=""></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const inputs=Array.prototype.slice.call(root.querySelectorAll("input[data-key]")),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const x={};inputs.forEach(i=>x[i.dataset.key]=api.parseNumber(i.value));const r=compute(x);if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("힘",`${api.formatNumber(r.value,8)} N`,"F = m × a"));});}
w.HM_CALC.register(ID,{compute,render});})(window);
